function teleportToNearestCharacter()
{
    // Get the nearest player
    var nearestPlayer = is_nearest_player(Photon.player);
    // If the nearest player is not null, teleport the player to the nearest player's position
    if (nearestPlayer != null)
    {
        Photon.player.teleportTo(nearestPlayer.getPosition());
    }
}

