void convertMarkdownToHtml(std::string& markdown) 
{
    markdown = markdown.replace("*", "em");
    markdown = markdown.replace("_", "i");
    markdown = markdown.replace("[", "br");
    markdown = markdown.replace("]", "br");
    markdown = markdown.replace("-", "span");
    markdown = markdown.replace("> ", "&gt;");
    markdown = markdown.replace("< ", "&lt;");
