}

function isPrime(arr) {
    const isPrime = arr => arr.length > 1 && arr[0] === arr[1] && arr[2] === arr[3] && arr[4] === arr[5];
    return arr.some(isPrime);
}

const arr = [5, 4, 3, 2, 1];

if (isPrime(arr)) {
